// src/services/api.js
const fakeTasks = [
  {
    id: "t001",
    title: "Design homepage layout",
    description: "Create wireframes and mockups for the main landing page",
    status: "completed",
    priority: "high",
    createdAt: "2026-06-01T09:00:00Z",
    updatedAt: "2026-06-03T11:00:00Z"
  },
  {
    id: "t002",
    title: "Setup Express server",
    description: "Initialize Node.js project with Express and basic middleware",
    status: "completed",
    priority: "high",
    createdAt: "2026-06-02T10:00:00Z",
    updatedAt: "2026-06-02T15:00:00Z"
  },
  {
    id: "t003",
    title: "Build task API endpoints",
    description: "Create GET POST PUT DELETE routes for tasks",
    status: "in-progress",
    priority: "high",
    createdAt: "2026-06-03T08:30:00Z",
    updatedAt: "2026-06-04T10:00:00Z"
  },
  {
    id: "t004",
    title: "Setup React project with Vite",
    description: "Initialize frontend with Vite and Tailwind CSS",
    status: "completed",
    priority: "medium",
    createdAt: "2026-06-04T09:00:00Z",
    updatedAt: "2026-06-04T12:00:00Z"
  },
  {
    id: "t005",
    title: "Create TaskForm component",
    description: "Build reusable form for creating and editing tasks",
    status: "in-progress",
    priority: "high",
    createdAt: "2026-06-05T10:00:00Z",
    updatedAt: "2026-06-06T09:00:00Z"
  },
  {
    id: "t006",
    title: "Build TaskList table view",
    description: "Display all tasks in a table with status and priority badges",
    status: "in-progress",
    priority: "high",
    createdAt: "2026-06-06T08:00:00Z",
    updatedAt: "2026-06-07T10:00:00Z"
  },
  {
    id: "t007",
    title: "Add filter by status feature",
    description: "Allow users to filter tasks by status",
    status: "pending",
    priority: "medium",
    createdAt: "2026-06-07T11:00:00Z",
    updatedAt: "2026-06-08T09:00:00Z"
  },
  {
    id: "t008",
    title: "Write unit tests for validation",
    description: "Test task title description status and priority",
    status: "pending",
    priority: "medium",
    createdAt: "2026-06-08T09:00:00Z",
    updatedAt: "2026-06-08T09:00:00Z"
  },
  {
    id: "t009",
    title: "Handle loading and error states",
    description: "Show spinner while fetching and error message if API fails",
    status: "pending",
    priority: "medium",
    createdAt: "2026-06-09T10:00:00Z",
    updatedAt: "2026-06-09T10:00:00Z"
  },
  {
    id: "t010",
    title: "Make UI responsive for mobile",
    description: "Ensure layout works on small screens",
    status: "pending",
    priority: "low",
    createdAt: "2026-06-10T08:00:00Z",
    updatedAt: "2026-06-10T08:00:00Z"
  }
];

let tasks = [...fakeTasks];

export const getTasks = () =>
  Promise.resolve({ data: { data: tasks } });

export const createTask = (data) => {
  const newTask = {
    ...data,
    id: Math.random().toString(36).slice(2),
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  tasks.push(newTask);
  return Promise.resolve({ data: { data: newTask } });
};

export const updateTask = (id, data) => {
  tasks = tasks.map(t =>
    t.id === id ? { ...t, ...data, updatedAt: new Date().toISOString() } : t
  );
  const updated = tasks.find(t => t.id === id);
  return Promise.resolve({ data: { data: updated } });
};

export const deleteTask = (id) => {
  tasks = tasks.filter(t => t.id !== id);
  return Promise.resolve({ data: { success: true } });
};
